import { C } from '../data/defaults';
import PortfolioBoard from './PortfolioBoard';

export default function ArtistModal({ artist, onClose }) {
  if (!artist) return null;
  const a = artist;
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal-box" style={{ maxWidth: 640 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
          <div className="label label-teal">ARTIST PROFILE</div>
          <button onClick={onClose} className="btn btn-outline btn-sm">✕ Close</button>
        </div>

        <div className="profile-hero" style={{ marginBottom: 0 }}>
          <div style={{ display: 'flex', alignItems: 'flex-start', gap: 16, marginBottom: 16 }}>
            <div className="profile-avatar" style={{ background: C.tealL }}>🎸</div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 20, fontWeight: 500, marginBottom: 4 }}>{a.name}</div>
              <div style={{ fontSize: 13, color: '#666' }}>{a.genre} · {a.city} · {a.members === '1' ? 'Solo artist' : a.members + '-piece band'}</div>
              {a.exp && <div style={{ fontSize: 12, color: '#aaa', marginTop: 2 }}>{a.exp} years gigging</div>}
              {a.instruments && (
                <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginTop: 8 }}>
                  {a.instruments.split(',').map((t, i) => <span key={i} className="tag tag-gray">{t.trim()}</span>)}
                </div>
              )}
            </div>
          </div>
          {a.bio && <p style={{ fontSize: 14, color: '#555', lineHeight: 1.8, marginBottom: 12 }}>{a.bio}</p>}
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
            {a.instagram && <a href={`https://instagram.com/${a.instagram.replace('@', '')}`} target="_blank" rel="noreferrer" style={{ fontSize: 12, color: C.teal, textDecoration: 'none' }}>📷 {a.instagram}</a>}
            {a.yt && <a href={a.yt} target="_blank" rel="noreferrer" style={{ fontSize: 12, color: C.teal, textDecoration: 'none' }}>▶ Listen / Watch</a>}
          </div>
        </div>

        {((a.portfolio||[]).length > 0 || (a.photos||[]).length > 0) && (
          <>
            <div className="section-title">PORTFOLIO BOARD</div>
            <PortfolioBoard portfolio={a.portfolio || []} photos={a.photos || []} isOwner={false} />
          </>
        )}
      </div>
    </div>
  );
}
